import { HttpClient } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { map, shareReplay } from 'rxjs/operators';
import { Artwork } from '../interfaces/artwork.interface';
import { generatedDataUrl } from './generated-data-url';

@Injectable({
  providedIn: 'root'
})
export class ArtworkService {
  private readonly artworks$: Observable<Artwork[]>;

  constructor(private readonly http: HttpClient) {
    this.artworks$ = this.http.get<Artwork[]>(generatedDataUrl('artworks.json')).pipe(shareReplay(1));
  }

  getArtworks(): Observable<Artwork[]> {
    return this.artworks$;
  }

  getArtworkBySlug(slug: string): Observable<Artwork | undefined> {
    return this.artworks$.pipe(
      map((artworks) => artworks.find((artwork) => artwork.slug === slug))
    );
  }

  getPaintings(): Observable<Artwork[]> {
    return this.artworks$.pipe(
      map((artworks) =>
        artworks.filter((artwork) => artwork.type === 'painting' || artwork.type === 'other')
      )
    );
  }

  getDrawings(): Observable<Artwork[]> {
    return this.artworks$.pipe(
      map((artworks) =>
        artworks.filter(
          (artwork) =>
            artwork.type === 'drawing' || artwork.type === 'work_on_paper'
        )
      )
    );
  }
}
